        intelligence: parseFloat(_.get(variables, `${basePath}智力[0]`, 0)) || 0,
        luck: parseFloat(_.get(variables, `${basePath}幸運[0]`, 0)) || 0
    };

    // 2. 計算裝備提供的屬性加成
    const equipmentBonuses = {
        strength: 0, agility: 0, stamina: 0, spirit: 0, intelligence: 0, luck: 0
