    }

    // 3. 計算最終總屬性
    const totalStats = {
        strength: baseStats.strength + equipmentBonuses.strength,
        agility: baseStats.agility + equipmentBonuses.agility,
        stamina: baseStats.stamina + equipmentBonuses.stamina,
