        '閃避率[0]': () => Math.min(totalStats.agility * 0.5, 99),
        '暴擊率[0]': () => parseFloat(((totalStats.agility * 0.2) + (totalStats.luck * 0.3) + (totalStats.intelligence * 0.1)).toFixed(2))
    };

